import{_ as a,o as i,c as t,ag as l}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"What Is LinkedQL","description":"","frontmatter":{},"headers":[],"relativePath":"overview.md","filePath":"overview.md"}'),r={name:"overview.md"};function o(n,e,s,c,d,h){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="what-is-linkedql" tabindex="-1">What Is LinkedQL <a class="header-anchor" href="#what-is-linkedql" aria-label="Permalink to &quot;What Is LinkedQL&quot;">​</a></h1><p>LinkedQL is a modern SQL interface that drops into any JavaScript application or agentic workflows with advanced capabilities.</p><p>At its simplest, it gives you a stable way to talk to data:</p><ul><li><code>query()</code></li><li><code>stream()</code></li><li><code>transaction()</code></li><li><code>wal.subscribe()</code></li></ul><p>But the same gives you a much broader system:</p><ul><li>live queries as a first-class runtime capability</li><li>powerful SQL language shorthands for relationships, JSON, and more</li><li>cross-runtime quering via <code>EdgeClient</code> (e.g. client -&gt; server querying)</li><li>an embeddable local SQL engine named FlashQL, that itself enables...</li><li>federation, materialization, and bidirectional sync</li><li>version safety and point-in-time replay</li><li>and more</li></ul><h2 id="why-linkedql" tabindex="-1">Why LinkedQL <a class="header-anchor" href="#why-linkedql" aria-label="Permalink to &quot;Why LinkedQL&quot;">​</a></h2><p>If you&#39;ve built a realworld system before, you most certainly stacked up tools and capability layers on top of SQL:</p><ul><li>ORMs for relationships</li><li>schema mappers and a migration system</li><li>subscription servers like GraphQL for live updates</li><li>custom local caches and sync layers for offline-first apps</li><li>and probably more</li></ul><p>The idea with LinkedQL is to be what SQL can be: a self-aware, reactive system that can directly answer modern application flows.</p><p>LinkedQL&#39;s direction is to absorb more of SQL&#39;s compensatory layers into the language.</p><h2 id="the-three-big-areas" tabindex="-1">The Three Big Areas <a class="header-anchor" href="#the-three-big-areas" aria-label="Permalink to &quot;The Three Big Areas&quot;">​</a></h2><h3 id="common-client-contract" tabindex="-1">Common Client Contract <a class="header-anchor" href="#common-client-contract" aria-label="Permalink to &quot;Common Client Contract&quot;">​</a></h3><p>Across runtimes, LinkedQL tries to keep the core application contract stable:</p><ul><li>query normally with <code>query()</code></li><li>do live queries with <code>query({ live: true })</code></li><li>do pull-based queries with <code>stream()</code></li><li>do explicit transactional work with <code>transaction()</code></li><li>subscribe to table-level commits with <code>wal.subscribe()</code></li></ul><p>See: <a href="/docs/query-api">Query Interface</a></p><h3 id="language-capabilities" tabindex="-1">Language Capabilities <a class="header-anchor" href="#language-capabilities" aria-label="Permalink to &quot;Language Capabilities&quot;">​</a></h3><p>LinkedQL extends SQL with application-oriented language features such as:</p><ul><li><a href="/capabilities/deeprefs">DeepRefs</a></li><li><a href="/capabilities/json-literals">JSON Literals</a></li><li><a href="/capabilities/version-binding">Version Binding</a></li></ul><p>These are about expressing richer intent in the query itself instead of pushing that intent into external glue code.</p><h3 id="runtime-capabilities" tabindex="-1">Runtime Capabilities <a class="header-anchor" href="#runtime-capabilities" aria-label="Permalink to &quot;Runtime Capabilities&quot;">​</a></h3><p>LinkedQL also extends the runtime side of the database contract:</p><ul><li><a href="/capabilities/live-queries">Live Queries</a></li><li><a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a></li></ul><p>These collapse existing tall tooling stacks, capability layers, and large scale glue code into a single application-ready primitive.</p><h2 id="flashql-s-role" tabindex="-1">FlashQL&#39;s Role <a class="header-anchor" href="#flashql-s-role" aria-label="Permalink to &quot;FlashQL&#39;s Role&quot;">​</a></h2><p>FlashQL is an answer to an everyday question: how do I run SQL locally from the browser/edge runtime/current process? How do I optionally back the local instance up with an upstream database, plus: optionally get both instances in sync?</p><p>It gives you:</p><ul><li>a local SQL engine, with pluggable persistence backends</li><li>federation, materialization, and sync with a strong conflict handling model</li><li>historical data and point-in-time replays</li></ul><p>See:</p><ul><li><a href="/flashql">FlashQL</a></li><li><a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a></li><li><a href="/docs/integration-patterns">Sync Integration Patterns</a></li></ul><h2 id="where-to-start" tabindex="-1">Where to Start <a class="header-anchor" href="#where-to-start" aria-label="Permalink to &quot;Where to Start&quot;">​</a></h2><ul><li>If you want the quickest entry, go to <a href="/docs">Getting Started</a></li><li>If you want the universal method contract, go to <a href="/docs/query-api">Query Interface</a></li><li>If you want the capabilities now, go to <a href="/capabilities">Capabilities Overview</a></li><li>If you want the local runtime story, go to <a href="/flashql">FlashQL</a></li></ul>',32)])])}const f=a(r,[["render",o]]);export{u as __pageData,f as default};
